import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract_packages(data):
    result = {}
    for proj in data.get('projects', []):
        name = proj['path'].split('/')[-1]
        pkgs = {}
        for fw in proj.get('frameworks', []):
            tf = fw['framework']
            for pkg in fw.get('topLevelPackages', []):
                key = (pkg['id'], tf)
                pkgs[key] = pkg.get('resolvedVersion', pkg.get('requestedVersion',''))
        result[name] = pkgs
    return result

b = extract_packages(baseline)
a = extract_packages(after)

changes = []
unchanged = []
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    bp = b.get(proj, {})
    ap = a.get(proj, {})
    for key in sorted(set(list(bp.keys()) + list(ap.keys()))):
        bv = bp.get(key, 'N/A')
        av = ap.get(key, 'N/A')
        if bv != av:
            changes.append((proj, key[0], key[1], bv, av))
        else:
            unchanged.append((proj, key[0], key[1], bv))

print('=== CHANGES ===')
for c in changes:
    print(f'{c[0]} | {c[1]} ({c[2]}) | {c[3]} -> {c[4]}')
print(f'\\nTotal changes: {len(changes)}')
print(f'Total unchanged: {len(unchanged)}')
"
", "description": "Compare baseline vs after packages", "initial_wait": 30}

